55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const COMPONENT_PRICE = 25;
64	const BLOCK_SIZE = 3;
65	const BLOCK_PRICE = 60;
66	const COMPONENT_TYPES = new Set(["rune"]);
67	
68	const FIRST_INSURANCE_SURCHARGE = 1.1;
69	const PROCESSING_FEE = 5;
70	const FLOAT_PRECISION_DIGITS = 6;
71	
72	const componentBase = (count: number): number => {
73	  return count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_PRICE;
74	};
75	
76	const countByType = (items: Item[]): Map<string, number> => {
77	  const counts = new Map<string, number>();
78	  for (const item of items) {
79	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
80	  }
81	  return counts;
82	};
83	
84	const itemBaseTotal = (items: Item[]): number => {
85	  let total = 0;
86	  for (const [type, count] of countByType(items)) {
87	    total += COMPONENT_TYPES.has(type)
88	      ? componentBase(count)
89	      : BASE_PREMIUM[type] * count;
90	  }
91	  return total;
92	};
93	
94	const quotePremium = (step: QuoteStep): number => {
95	  const itemTotal = itemBaseTotal(step.items) * FIRST_INSURANCE_SURCHARGE;
96	  const premium = itemTotal + PROCESSING_FEE;
97	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
98	};
99	
100	export const runScenario = (scenario: Scenario): ScenarioResult => {
101	  return {
102	    results: scenario.steps.map((step) => ({
103	      premium: quotePremium(step as QuoteStep),
104	    })),
105	  };
106	};
